// ../core/mediaMetadata.ts
function renameFolderInMediaMetadata(mediaMetadata, from, to) {
  const fromNormalized = from.endsWith("/") ? from : from + "/";
  const toNormalized = to.endsWith("/") ? to : to + "/";
  const result = structuredClone(mediaMetadata);
  if (result.mediaFolderPath) {
    const mediaFolderPathNormalized = result.mediaFolderPath.endsWith("/") ? result.mediaFolderPath : result.mediaFolderPath + "/";
    if (result.mediaFolderPath === fromNormalized.slice(0, -1)) {
      result.mediaFolderPath = toNormalized.slice(0, -1);
    } else if (mediaFolderPathNormalized.startsWith(fromNormalized)) {
      result.mediaFolderPath = toNormalized + result.mediaFolderPath.slice(fromNormalized.length);
    }
  }
  if (result.files) {
    result.files = result.files.map((file2) => {
      if (file2.startsWith(fromNormalized)) {
        return toNormalized + file2.slice(fromNormalized.length);
      }
      return file2;
    });
  }
  if (result.mediaFiles) {
    result.mediaFiles = result.mediaFiles.map((mediaFile) => {
      if (mediaFile.absolutePath.startsWith(fromNormalized)) {
        return {
          ...mediaFile,
          absolutePath: toNormalized + mediaFile.absolutePath.slice(fromNormalized.length)
        };
      }
      return mediaFile;
    });
  }
  return result;
}
function updateMediaMetadataAfterRename(mediaMetadata, renameMappings) {
  const renameMap = new Map;
  for (const { from, to } of renameMappings) {
    renameMap.set(Path.posix(from), Path.posix(to));
  }
  const updatedFiles = mediaMetadata.files?.map((file2) => {
    const normalizedFile = Path.posix(file2);
    return renameMap.get(normalizedFile) ?? file2;
  });
  const updatedMediaFiles = mediaMetadata.mediaFiles?.map((mediaFile) => {
    const normalizedPath = Path.posix(mediaFile.absolutePath);
    const newPath = renameMap.get(normalizedPath);
    if (newPath) {
      return {
        ...mediaFile,
        absolutePath: newPath
      };
    }
    return mediaFile;
  });
  const fullyUpdatedMediaFiles = updatedMediaFiles?.map((mediaFile) => {
    if (mediaFile.subtitleFilePaths || mediaFile.audioFilePaths) {
      const updatedSubtitlePaths = mediaFile.subtitleFilePaths?.map((subtitlePath) => {
        const normalizedPath = Path.posix(subtitlePath);
        return renameMap.get(normalizedPath) ?? subtitlePath;
      });
      const updatedAudioPaths = mediaFile.audioFilePaths?.map((audioPath) => {
        const normalizedPath = Path.posix(audioPath);
        return renameMap.get(normalizedPath) ?? audioPath;
      });
      return {
        ...mediaFile,
        subtitleFilePaths: updatedSubtitlePaths,
        audioFilePaths: updatedAudioPaths
      };
    }
    return mediaFile;
  });
  return {
    ...mediaMetadata,
    files: updatedFiles,
    mediaFiles: fullyUpdatedMediaFiles
  };
}

