var renameFolderRequestSchema = exports_external.object({
  from: exports_external.string().min(1, "Source folder path is required, in POSIX format"),
  to: exports_external.string().min(1, "Destination folder path is required, in POSIX format")
});
async function doRenameFolder(body, config2 = {}) {
  try {
    const validationResult = renameFolderRequestSchema.safeParse(body);
    if (!validationResult.success) {
      return {
        error: `Validation Failed: ${validationResult.error.issues.map((i) => i.message).join(", ")}`
      };
    }
    const { from, to } = validationResult.data;
    const fromAsPosix = Path.posix(from);
    const toAsPosix = Path.posix(to);
    if (!await isMediaFolderManaged(from, config2)) {
      config2.logger?.error({ from: fromAsPosix, to: toAsPosix }, "[renameFolder] source folder is not managed by SMM");
      return {
        error: `${fromAsPosix} is not managed by SMM`
      };
    }
    const appDataDir = resolveAppDataDir(config2);
    if (!appDataDir) {
      return { error: "appDataDir is not configured" };
    }
    const mediaMetadata = await readMediaMetadataCache(appDataDir, fromAsPosix);
    if (!mediaMetadata) {
      config2.logger?.error({ from: fromAsPosix, to: toAsPosix }, "[renameFolder] media metadata not found");
      return {
        error: `Media metadata not found: ${from}`
      };
    }
    const updatedMetadata = renameFolderInMediaMetadata(mediaMetadata, fromAsPosix, toAsPosix);
    await writeMediaMetadataCache(appDataDir, updatedMetadata);
    await deleteMediaMetadataCache(appDataDir, fromAsPosix);
    const userConfig = await readUserConfig(config2);
    const newUserConfig = renameFolderInUserConfig(userConfig, fromAsPosix, toAsPosix);
    await writeUserConfigToDisk(config2, newUserConfig);
    await rename(Path.toPlatformPath(fromAsPosix), Path.toPlatformPath(toAsPosix));
    config2.logger?.info({ from: fromAsPosix, to: toAsPosix }, "[renameFolder] renamed media folder");
    return {};
  } catch (error48) {
    const message = error48 instanceof Error ? error48.message : "Unknown error";
    config2.logger?.error({ error: message }, "[renameFolder] unexpected error");
    return {
      error: `Unexpected Error: ${message}`
    };
  }
}
// ../core/getMediaFolder.ts
function getMediaFolder(filePath, folderPaths) {
  const filePathNorm = new Path(filePath).abs("posix").replace(/^\/[A-Za-z](?::|\/)/, "");
  for (const folder of folderPaths) {
    const folderNorm = new Path(folder).abs("posix").replace(/^\/[A-Za-z](?::|\/)/, "");
    const prefix = folderNorm.endsWith("/") ? folderNorm : `${folderNorm}/`;
    if (filePathNorm === folderNorm || filePathNorm.startsWith(prefix)) {
      return folder;
    }
  }
  return null;
}

// src/renameFileExecution.ts
import { mkdir as mkdir4, rename as rename2, stat as stat4 } from "node:fs/promises";
import path7 from "node:path";
async function directoryExists(dirPath) {
  try {
    const stats = await stat4(dirPath);
    return stats.isDirectory();
  } catch {
    return false;
  }
}
async function executeRenameOperation(from, to) {
  const fromPathPlatform = new Path(from).platformAbsPath();
  const toPathPlatform = new Path(to).platformAbsPath();
  try {
    const destDir = path7.dirname(toPathPlatform);
    await mkdir4(destDir, { recursive: true });
    if (!await directoryExists(destDir)) {
      return {
        success: false,
        error: `Destination directory does not exist and could not be created: ${destDir}`
      };
    }
    await rename2(fromPathPlatform, toPathPlatform);
    return { success: true };
  } catch (error48) {
    const errorMessage = error48 instanceof Error ? error48.message : "Unknown error";
    return {
      success: false,
      error: errorMessage.includes("ENOENT") ? `Source file does not exist: ${fromPathPlatform}` : errorMessage
    };
  }
}
async function executeBatchRenameOperations(renameMappings, _options = {}) {
  if (renameMappings.length === 0) {
    return {
      success: false,
      errors: ["No rename operations provided"]
    };
  }
  const errors4 = [];
  const successfulRenames = [];
  for (const renameMapping of renameMappings) {
    const result = await executeRenameOperation(renameMapping.from, renameMapping.to);
    if (result.success) {
      successfulRenames.push(renameMapping);
    } else {
      errors4.push(`Failed to rename "${renameMapping.from}" to "${renameMapping.to}": ${result.error ?? "Unknown error"}`);
    }
  }
  if (errors4.length > 0) {
    return {
      success: false,
      errors: errors4,
      successfulRenames: successfulRenames.length > 0 ? successfulRenames : undefined
    };
  }
  return {
    success: true,
    successfulRenames
  };
}

